script.text:
      /* <flatten type="Javascript"> */
function active$DefinitionOfPeriodicAllocationEntries(f) {
  f.add_onResponseComplete(on$DefinitionOfPeriodicAllocationEntries$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onTabChanged);
  f._tabContainer._loaded = true;
  setUnitInformation(f);
}
function close$DefinitionOfPeriodicAllocationEntries(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onTabChanged);} catch (ex) {}
  try {f.remove_onResponseComplete(on$DefinitionOfPeriodicAllocationEntries$ResponseComplete)} catch (ex) {}
}
function on$DefinitionOfPeriodicAllocationEntries$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'DebitAccount':
      f._drAcct = result[0].Value;
      setObjectFormAllowNull(f);
      break;
    case 'CreditAccount':
      f._crAcct = result[0].Value;
      setObjectFormAllowNull(f);
      break;
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_bt');
      break;
    default:
      break;
  }
}
function onTabChanged(sender, e) {sender.parentForm.focusWhenTabChanged(['loai_pb', 'ma_kh', 'ghi_chu']);}
function setUnitInformation(f) {
  if (f._action == 'New') {
    f.setItemValues('ma_dvcs, ten_dvcs%l', [f._unitCode, f._unitName]);
    if (f.grid._activeRow <= 0) f.setItemValues('ma_nt, ten_nt%l', [f._currencyCode, f._currencyName]);
    f._drAcct = f._crAcct = 0;
  }
  if (f._action != 'View') setObjectFormAllowNull(f);
}
function onChange$DefinitionOfPeriodicAllocationEntries(o) {
  var f = o.parentForm, name = o.field.Name, nPeriod = f.getItemValue('so_ky_pb'), dStart = f.getItemValue('ngay_bd', null, null, true);
  var dStartMonth, dStartYear, dTo;
  if ((dStart) && (nPeriod != 0)) {
    dStartMonth = dStart.getMonth() + nPeriod, dStartYear = dStart.getFullYear();
    dTo = new Date(dStartYear, dStartMonth, 0);
  }
  switch (name) {
    case 'ngay_bd':
      f.setItemValue('ngay_kt', dTo);
      f.getItem('ngay_kt').focus();
      f.live(f.getItem('ngay_kt'));
      break;
    case 'so_ky_pb':
      f.executeExpression(['[tien_pb_ky_nt]:=[so_ky_pb]==0 ? 0:([tien_nt]/[so_ky_pb])',
        '[tien_pb_ky]:=[so_ky_pb]==0 ? 0:([tien]/[so_ky_pb])',
        '[tien_cl_nt]:=[tien_nt] - [tien_pb_nt]',
        '[tien_cl]:=[tien] - [tien_pb]'
      ]);
      f.setItemValue('ngay_kt', dTo);
      break;
    case 'tien':
      f.executeExpression(['[tien_pb_ky]:=[so_ky_pb]==0 ? 0:([tien]/[so_ky_pb])', '[tien_cl]:=[tien] - [tien_pb]']);
      break;
    case 'tien_nt':
      f.executeExpression(['[tien_pb_ky_nt]:=[so_ky_pb]==0 ? 0:([tien_nt]/[so_ky_pb])','[tien_cl_nt]:=[tien_nt] - [tien_pb_nt]']);
      break;
    case 'tien_pb':
      f.executeExpression(['[tien_cl]:=[tien] - [tien_pb]']);
      break;
    case 'tien_pb_nt':
      f.executeExpression(['[tien_cl_nt]:=[tien_nt] - [tien_pb_nt]']);
      break;
    case 'tk_no':
      f.request('Account', 'DebitAccount', [['tk', 'String', f.getItemValue('tk_no')]], o);
      break;
    case 'tk_co':
      f.request('Account', 'CreditAccount', [['tk', 'String', f.getItemValue('tk_co')]], o);
      break;
    default:
      break;
  }
}
function setObjectFormAllowNull(f) {
  var o = f.getItem('ma_kh'), b = (f._drAcct || f._crAcct);
  var grandNode = o.parentNode.parentNode;
  o.field.AllowNulls = !b;
  if (b) {
    Sys.UI.DomElement.addCssClass(grandNode, 'Required');
    Sys.UI.DomElement.addCssClass(grandNode, f._id);
  } else {Sys.UI.DomElement.removeCssClass(grandNode, 'Required');}
}
/* </flatten> */
      &ScriptIrregular;
